// ПОПОЛНЕНИЕ: после входа ведём в счёт фирмы и вписываем сумму с барабана.
// Перенесено из EtollWebScreen.gotoFinancing — здесь ОТДЕЛЬНО, баланс не трогаем.
// Путь: (вошли в фирму) → financing/list → prepaid-счёт → Top up →
// вписать сумму → «Далее» (до формы карты; оплату подтверждает водитель сам).
Future<void> _topUpStep(Uri? url) async {
  if (_controller == null || _topUpDone) return;
  final u = url?.toString() ?? '';
  final lu = u.toLowerCase();
  if (lu.contains('login')) return; // ещё на странице входа

  final m = RegExp(r'/subject/(\d+)').firstMatch(u);
  if (m != null) _subjectId = m.group(1) ?? _subjectId;
  final sid =
      widget.subjectId.trim().isNotEmpty ? widget.subjectId.trim() : _subjectId;

  // 1) Уже на странице пополнения — вписать сумму и нажать «Далее».
  if (lu.contains('/financing/prepaid') && lu.contains('/top-up')) {
    _topUpDone = true;
    final amt = (await BalanceStore.topUpAmount()).trim();
    if (amt.isEmpty) return;
    await Future.delayed(const Duration(milliseconds: 900));
    await _controller?.evaluateJavascript(source: '''
      (function(){try{
        var want='$amt';
        var ins=document.querySelectorAll('input[type="text"],input[type="number"],input:not([type])');
        var target=null;
        for(var i=0;i<ins.length;i++){
          var t=ins[i];
          if(t.offsetParent===null) continue;
          if(t.type==='password') continue;
          target=t;
        }
        if(target){
          var setter=Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype,'value').set;
          setter.call(target, want);
          target.dispatchEvent(new Event('input',{bubbles:true}));
          target.dispatchEvent(new Event('change',{bubbles:true}));
          target.dispatchEvent(new Event('blur',{bubbles:true}));
        }
      }catch(e){}})();
    ''');
    // Жмём «Далее/Продолжить» — доводим до выбора карты. Финальную оплату
    // (списание) водитель подтверждает сам — мы её не нажимаем.
    await Future.delayed(const Duration(milliseconds: 800));
    await _controller?.evaluateJavascript(source: r'''
      (function(){try{
        function realClick(el){try{var rc=el.getBoundingClientRect();
          var o={bubbles:true,cancelable:true,view:window,
            clientX:rc.left+rc.width/2,clientY:rc.top+rc.height/2};
          el.dispatchEvent(new MouseEvent('pointerdown',o));
          el.dispatchEvent(new MouseEvent('mousedown',o));
          el.dispatchEvent(new MouseEvent('mouseup',o));
          el.dispatchEvent(new MouseEvent('click',o));el.click();
        }catch(e){try{el.click();}catch(e2){}}}
        var words=['next','dalej','continue','kontynuuj','proceed',
          'przejdź','przejdz','далее','продолжить','дальше'];
        var btns=document.querySelectorAll('button,a,[role="button"],input[type="submit"],input[type="button"]');
        for(var i=0;i<btns.length;i++){var el=btns[i];
          if(el.offsetParent===null||el.disabled)continue;
          var t=(el.innerText||el.value||'').trim().toLowerCase();
          if(!t||t.length>24)continue;
          for(var w=0;w<words.length;w++){
            if(t===words[w]||t.indexOf(words[w])===0){realClick(el);return '1';}}}
        return '0';
      }catch(e){return '0';}})();
    ''');
    return;
  }

  if (sid.isEmpty) return; // ещё не внутри фирмы — ждём входа

  // 2) Вошли в фирму, но не на финансах — уходим на financing/list
  //    (прямая ссылка на список счётов SPA пускает, как в чтении баланса).
  if (!_wentFinancing && !lu.contains('/financing')) {
    _wentFinancing = true;
    final target =
        'https://mojekonto.etoll.gov.pl/selfservice/#/mobile/subject/$sid/manage/financing/list';
    try {
      await _controller?.loadUrl(urlRequest: URLRequest(url: WebUri(target)));
    } catch (_) {}
    return;
  }

  // 3) На финансах/счетах — кликами открываем prepaid-счёт и кнопку «Top up».
  if (lu.contains('/financing') || lu.contains('/billing-account')) {
    await _controller?.evaluateJavascript(source: r'''
      (function(){
        try{
          function realClick(el){
            try{
              var rc=el.getBoundingClientRect();
              var o={bubbles:true,cancelable:true,view:window,
                     clientX:rc.left+rc.width/2, clientY:rc.top+rc.height/2};
              el.dispatchEvent(new MouseEvent('pointerdown',o));
              el.dispatchEvent(new MouseEvent('mousedown',o));
              el.dispatchEvent(new MouseEvent('mouseup',o));
              el.dispatchEvent(new MouseEvent('click',o));
              el.click();
            }catch(e){ try{el.click();}catch(e2){} }
          }
          function byWords(words,maxLen){
            var els=document.querySelectorAll('a,button,[role="menuitem"],[role="button"],li,span,div,td,mat-card');
            for(var i=0;i<els.length;i++){
              var el=els[i];
              if(el.offsetParent===null) continue;
              var t=(el.innerText||el.textContent||'').trim().toLowerCase();
              if(!t||t.length>maxLen) continue;
              for(var w=0;w<words.length;w++){
                if(t===words[w]||t.indexOf(words[w])===0){
                  return el.closest('a,button,[role="button"],[role="menuitem"]')||el;
                }
              }
            }
            return null;
          }
          var href=(location.href||'').toLowerCase();
          var tu=byWords(['top up','top-up','doładuj','doladuj','zasil','wpłać','wplac','пополнить','пополнение','recharge'],24);
          if(tu){ realClick(tu); return 'topup'; }
          if(href.indexOf('/financing')>=0){
            var fa=document.querySelectorAll('a[href*="/financing/prepaid/"]');
            for(var i=0;i<fa.length;i++){ if(fa[i].offsetParent!==null){ realClick(fa[i]); return 'finacct'; } }
          }
          if(href.indexOf('/billing-account')>=0 && href.indexOf('/details')<0){
            var ba=document.querySelectorAll('a[href*="/billing-account/"]');
            for(var i=0;i<ba.length;i++){
              var h=(ba[i].getAttribute('href')||'');
              if(/billing-account\/\d+/.test(h) && ba[i].offsetParent!==null){ realClick(ba[i]); return 'acct'; }
            }
          }
          return 'none';
        }catch(e){return 'err';}
      })();
    ''');
  }
}

