import re

path = r'c:\projects\route_control\lib\main.dart'
s = open(path, encoding='utf-8').read()

# tokenizer: skip strings (incl raw + triple) and comments, count brackets
k = 0
L = len(s)
state = 'code'
quote = ''
raw = False
triple = False
sq = rd = cu = 0

while k < L:
    c = s[k]
    if state == 'code':
        if c == '/' and k + 1 < L and s[k + 1] == '/':
            state = 'line'; k += 2; continue
        if c == '/' and k + 1 < L and s[k + 1] == '*':
            state = 'block'; k += 2; continue
        if c == 'r' and k + 1 < L and s[k + 1] in ('"', "'"):
            quote = s[k + 1]; raw = True
            if s[k + 2:k + 5] == quote * 3:
                triple = True; k += 5
            else:
                triple = False; k += 2
            state = 'str'; continue
        if c in ('"', "'"):
            quote = c; raw = False
            if s[k + 1:k + 3] == quote * 2:
                triple = True; k += 3
            else:
                triple = False; k += 1
            state = 'str'; continue
        if c == '(':
            sq += 1
        elif c == ')':
            sq -= 1
        elif c == '[':
            rd += 1
        elif c == ']':
            rd -= 1
        elif c == '{':
            cu += 1
        elif c == '}':
            cu -= 1
        k += 1; continue
    if state == 'line':
        if c == '\n':
            state = 'code'
        k += 1; continue
    if state == 'block':
        if c == '*' and k + 1 < L and s[k + 1] == '/':
            state = 'code'; k += 2; continue
        k += 1; continue
    if state == 'str':
        if not raw and c == '\\':
            k += 2; continue
        if triple:
            if s[k:k + 3] == quote * 3:
                state = 'code'; k += 3; continue
            k += 1; continue
        else:
            if c == quote:
                state = 'code'; k += 1; continue
            if c == '\n':
                state = 'code'; k += 1; continue
            k += 1; continue

merge = len(re.findall(r'(?m)^(<{7}|={7}|>{7})', s))
classes = len(re.findall(r'(?m)^class \w+', s))
print('paren', sq, 'bracket', rd, 'brace', cu)
print('merge_markers', merge)
print('classes', classes)

