Future<void> _maybeSkipSplash() async {
  try {
    final prefs = await SharedPreferences.getInstance();
    final last = prefs.getInt('app_last_alive_ms') ?? 0;
    final recent = last > 0 &&
        (DateTime.now().millisecondsSinceEpoch - last) <
            const Duration(hours: 24).inMilliseconds;
    String? bal;
    try {
      bal = await BalanceStore.lastBalance();
