// ══════════════════════════════════════════════════════════════
class QuickAccessStore {
  static const String _kItems = 'quick_access_items';

  static Future<List<String>> items() async {
    final prefs = await SharedPreferences.getInstance();
    final raw = prefs.getString(_kItems);
    if (raw == null || raw.isEmpty) return [];
    try {
      final d = jsonDecode(raw);
      if (d is List) {
        return d.map((e) => e.toString()).where((e) => e.isNotEmpty).toList();
      }
    } catch (_) {}
    return [];
  }

  static Future<bool> has(String id) async {
    final list = await items();
    return list.contains(id);
  }

  static Future<void> setEnabled(String id, bool on) async {
    if (id.isEmpty) return;
    final prefs = await SharedPreferences.getInstance();
    final list = await items();
    final exists = list.contains(id);
    if (on && !exists) {
      list.add(id);
    } else if (!on && exists) {
      list.remove(id);
    } else {
      return; // ничего не изменилось
    }
    await prefs.setString(_kItems, jsonEncode(list));
    gQuickAccessNotifier.value++;
  }
}

