//  Сейчас заполнение пустое — экран показывает кэш; сбор подключается
//  отдельным шагом и НЕ затрагивает баланс/пополнение.
// ══════════════════════════════════════════════════════════════
class Vehicle {
  final String plate;    // госномер
  final String status;   // статус (active/inactive/«как в eTOLL»)
  final String category; // категория / устройство (OBU)
  const Vehicle({required this.plate, this.status = '', this.category = ''});

  Map<String, String> toJson() =>
      {'plate': plate, 'status': status, 'category': category};

  factory Vehicle.fromJson(Map m) => Vehicle(
        plate: (m['plate'] ?? '').toString(),
        status: (m['status'] ?? '').toString(),
        category: (m['category'] ?? '').toString(),
      );
}

class VehicleStore {
  static const String _kVehicles = 'etoll_vehicles_by_firm';
  static const String _kTime = 'etoll_vehicles_time_by_firm';

  static Future<Map<String, dynamic>> _read(String key) async {
    final prefs = await SharedPreferences.getInstance();
    final raw = prefs.getString(key);
    if (raw == null || raw.isEmpty) return {};
    try {
      final d = jsonDecode(raw);
      if (d is Map) return Map<String, dynamic>.from(d);
    } catch (_) {}
    return {};
  }

  static Future<List<Vehicle>> forFirm(String firmId) async {
    if (firmId.isEmpty) return [];
    final map = await _read(_kVehicles);
    final list = map[firmId];
    if (list is List) {
      return list
          .whereType<Map>()
          .map((e) => Vehicle.fromJson(e))
          .where((v) => v.plate.isNotEmpty)
          .toList();
    }
    return [];
  }

  static Future<DateTime?> timeForFirm(String firmId) async {
    if (firmId.isEmpty) return null;
    final map = await _read(_kTime);
    final ms = map[firmId];
    if (ms is int) return DateTime.fromMillisecondsSinceEpoch(ms);
    return null;
  }

  static Future<void> setForFirm(String firmId, List<Vehicle> vehicles) async {
    if (firmId.isEmpty) return;
    final prefs = await SharedPreferences.getInstance();
    final vmap = await _read(_kVehicles);
    vmap[firmId] = vehicles.map((v) => v.toJson()).toList();
    await prefs.setString(_kVehicles, jsonEncode(vmap));
    final tmap = await _read(_kTime);
    tmap[firmId] = DateTime.now().millisecondsSinceEpoch;
    await prefs.setString(_kTime, jsonEncode(tmap));
  }
}

