          var card=(anchors[i].closest&&anchors[i].closest('[class*="card"],[class*="party"],[class*="customer"],[class*="tile"],li,tr,article,section'))||anchors[i].parentElement;
          var ctext=card?(card.innerText||card.textContent||''):'';
