          var status=''; var ms=ctext.match(/(active|aktyw[a-zł]*|inactive|nieaktyw[a-zł]*)/i); if(ms) status=ms[1];
          var role=''; var mr=ctext.match(/(administrator|owner|w[lł]a[sś]ciciel|u[zż]ytkownik|user|viewer)/i); if(mr) role=mr[1];
