// Держит ОБА в дереве (IndexedStack): приложение (index 0) и мини-окно баланса
// (index 1). В PiP показываем баланс, но приложение остаётся ЖИВЫМ — поэтому при
// разворачивании из окошка открывается тот же экран, где остановились.
// (Пока активити жива в PiP. Если ОС выгрузит приложение из памяти — состояние
// не сохранится, это уже другой механизм.)
class _PipAwareApp extends StatelessWidget {
  final Floating floating;
  final Widget app;
  const _PipAwareApp({required this.floating, required this.app});

  @override
  Widget build(BuildContext context) {
    return StreamBuilder<PiPStatus>(
      stream: floating.pipStatusStream,
      initialData: PiPStatus.disabled,
      builder: (context, snapshot) {
        final inPip = snapshot.data == PiPStatus.enabled;
        return IndexedStack(
          index: inPip ? 1 : 0,
          sizing: StackFit.expand,
          children: [
            app,
            const PipBalanceView(),
          ],
        );
      },
    );
  }
}

